          {{ section.settings.cta_text }}
        </a>
      {%- endif -%}
    </div>
  {%- elsif status == 'before' -%}
    <div class="alsel-limited-sale-banner__inner alsel-limited-sale-banner__inner--before">
      <div class="alsel-limited-sale-banner__badge">開催予告</div>
