  .alsel-limited-sale-banner__inner--active { background: linear-gradient(135deg, {{ section.settings.bg_color }} 0%, {{ section.settings.accent_color }} 100%); }
  .alsel-limited-sale-banner__inner--before { background: #f1f5f9; color: #334155; }
  .alsel-limited-sale-banner__inner--ended { background: #e2e8f0; color: #475569; padding: 1.25rem; }
  .alsel-limited-sale-banner__badge { display: inline-block; padding: 0.3rem 1rem; background: rgba(255,255,255,0.95); color: {{ section.settings.accent_color }}; font-weight: 700; font-size: 0.85rem; border-radius: 9999px; margin-bottom: 1rem; letter-spacing: 0.05em; }
  .alsel-limited-sale-banner__title { font-size: clamp(1.4rem, 4.5vw, 2.4rem); font-weight: 700; line-height: 1.3; margin: 0 0 1rem; }
  .alsel-limited-sale-banner__discount { display: inline-flex; align-items: baseline; gap: 0.3rem; margin: 0.5rem 0 1rem; }
  .alsel-limited-sale-banner__discount-num { font-size: clamp(3rem, 10vw, 5.5rem); font-weight: 700; line-height: 1; }
  .alsel-limited-sale-banner__discount-unit { font-size: clamp(1.2rem, 3vw, 1.8rem); font-weight: 700; }
  .alsel-limited-sale-banner__sub { font-size: 1rem; line-height: 1.7; margin: 0 0 1rem; opacity: 0.95; }
  .alsel-limited-sale-banner__period { font-size: 0.95rem; font-weight: 600; margin: 0 0 1.25rem; opacity: 0.95; }
  .alsel-limited-sale-banner__countdown { display: flex; justify-content: center; gap: 0.6rem; margin: 0 0 1.5rem; flex-wrap: wrap; }
  .alsel-limited-sale-banner__cd-item { background: rgba(255,255,255,0.2); border-radius: 8px; padding: 0.6rem 0.8rem; min-width: 60px; backdrop-filter: blur(4px); }
  .alsel-limited-sale-banner__cd-num { display: block; font-size: 1.6rem; font-weight: 700; line-height: 1; font-variant-numeric: tabular-nums; }
  .alsel-limited-sale-banner__cd-label { display: block; font-size: 0.7rem; margin-top: 0.25rem; opacity: 0.9; }
  .alsel-limited-sale-banner__cta { display: inline-block; padding: 0.95rem 2.5rem; background: #ffffff; color: {{ section.settings.accent_color }}; text-decoration: none; border-radius: 9999px; font-weight: 700; font-size: 1rem; box-shadow: 0 4px 14px rgba(0,0,0,0.15); transition: transform 0.2s; }
  .alsel-limited-sale-banner__cta:hover { transform: translateY(-2px); }
