                <span class="alsel-review-carousel__star alsel-review-carousel__star--on" aria-hidden="true">★</span>
              {%- else -%}
                <span class="alsel-review-carousel__star" aria-hidden="true">★</span>
              {%- endif -%}
            {%- endfor -%}
          </div>

          {%- if block.settings.title != blank -%}
            <h3 class="alsel-review-carousel__title">{{ block.settings.title | escape }}</h3>
          {%- endif -%}

          {%- if block.settings.body != blank -%}
            <p class="alsel-review-carousel__body">{{ block.settings.body | escape | newline_to_br }}</p>
          {%- endif -%}

          <div class="alsel-review-carousel__person">
            {%- if block.settings.avatar != blank -%}
              {%- assign alt_1 = block.settings.name | escape -%}
{{ block.settings.avatar | image_url: width: 120 | image_tag: loading: 'lazy', class: 'alsel-review-carousel__avatar', alt: alt_1, widths: '60, 120, 180' }}
