  .alsel-seasonal-event__deco::after {
    content: '';
    position: absolute;
    top: -3px;
    width: 7px; height: 7px;
    border-radius: 50%;
    background: var(--se-accent);
  }
  .alsel-seasonal-event__deco::before { left: 0; }
  .alsel-seasonal-event__deco::after { right: 0; }

  .alsel-seasonal-event__inner {
