  }

  .alsel-seasonal-event__period {
    display: inline-flex;
    align-items: center;
    gap: 0.6rem;
    margin: 0 0 1.75rem;
    padding: 0.5rem 1.1rem;
    border: 1px solid rgba(255, 255, 255, 0.4);
    border-radius: 6px;
    font-size: 0.9rem;
  }
  .alsel-seasonal-event__period-label {
    background: var(--se-accent);
    color: #fff;
    padding: 0.15rem 0.55rem;
    border-radius: 3px;
    font-size: 0.75rem;
    font-weight: 700;
  }

  .alsel-seasonal-event__cta {
    display: inline-flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.95rem 2.2rem;
    background: var(--se-cta-bg);
    color: var(--se-cta-color);
    text-decoration: none;
    border-radius: 9999px;
    font-weight: 700;
    font-size: 1rem;
    transition: transform 0.2s ease, box-shadow 0.2s ease;
    box-shadow: 0 4px 14px rgba(0, 0, 0, 0.25);
  }
  .alsel-seasonal-event__cta:hover { transform: translateY(-2px); box-shadow: 0 6px 18px rgba(0, 0, 0, 0.3); }
  .alsel-seasonal-event__cta-arrow { transition: transform 0.2s ease; }
