<section class="alsel-subscription-benefits" aria-label="{{ section.settings.heading | escape }}">
  <div class="alsel-subscription-benefits__inner">
    {%- if section.settings.badge != blank -%}
      <span class="alsel-subscription-benefits__badge">{{ section.settings.badge }}</span>
    {%- endif -%}
    {%- if section.settings.heading != blank -%}
      <h2 class="alsel-subscription-benefits__heading">{{ section.settings.heading }}</h2>
    {%- endif -%}
    {%- if section.settings.lead != blank -%}
      <p class="alsel-subscription-benefits__lead">{{ section.settings.lead }}</p>
    {%- endif -%}

    {%- if section.settings.show_price_compare -%}
      <div class="alsel-subscription-benefits__compare" role="group" aria-label="価格比較">
        <div class="alsel-subscription-benefits__price-box alsel-subscription-benefits__price-box--regular">
          <span class="alsel-subscription-benefits__price-label">通常購入</span>
          <span class="alsel-subscription-benefits__price-value">{{ section.settings.regular_price }}</span>
        </div>
        <div class="alsel-subscription-benefits__arrow" aria-hidden="true">▶</div>
        <div class="alsel-subscription-benefits__price-box alsel-subscription-benefits__price-box--sub">
          <span class="alsel-subscription-benefits__price-label">定期購入</span>
          <span class="alsel-subscription-benefits__price-value">{{ section.settings.sub_price }}</span>
          {%- if section.settings.discount_text != blank -%}
            <span class="alsel-subscription-benefits__discount">{{ section.settings.discount_text }}</span>
          {%- endif -%}
        </div>
      </div>
    {%- endif -%}

    {%- if section.blocks.size > 0 -%}
      <ul class="alsel-subscription-benefits__grid">
        {%- for block in section.blocks -%}
          <li class="alsel-subscription-benefits__card" {{ block.shopify_attributes }}>
            {%- if block.settings.icon != blank -%}
              {%- assign alt_1 = block.settings.title | escape -%}
{{ block.settings.icon | image_url: width: 200 | image_tag: loading: 'lazy', class: 'alsel-subscription-benefits__icon', alt: alt_1, widths: '100, 200' }}
            {%- else -%}
              <div class="alsel-subscription-benefits__num" aria-hidden="true">{{ forloop.index }}</div>
            {%- endif -%}
            <h3 class="alsel-subscription-benefits__card-title">{{ block.settings.title }}</h3>
            <p class="alsel-subscription-benefits__card-body">{{ block.settings.body }}</p>
          </li>
        {%- endfor -%}
      </ul>
    {%- endif -%}

    {%- if section.settings.cta_text != blank and section.settings.cta_link != blank -%}
      <div class="alsel-subscription-benefits__cta-wrap">
        <a class="alsel-subscription-benefits__cta" href="{{ section.settings.cta_link }}" aria-label="{{ section.settings.cta_text | escape }}">
          {{ section.settings.cta_text }}
        </a>
        {%- if section.settings.cta_note != blank -%}
          <p class="alsel-subscription-benefits__cta-note">{{ section.settings.cta_note }}</p>
        {%- endif -%}
      </div>
    {%- endif -%}
  </div>
</section>

<style>
