  }
  .alsel-subscription-benefits__card {
    background: #fff; padding: 1.75rem 1.25rem; border-radius: 16px;
    box-shadow: 0 4px 16px rgba(15, 23, 42, 0.06); text-align: center;
  }
  .alsel-subscription-benefits__icon { width: 72px; height: 72px; object-fit: contain; margin: 0 auto 1rem; display: block; }
  .alsel-subscription-benefits__num {
    width: 56px; height: 56px; border-radius: 50%; background: var(--accent); color: #fff;
    display: flex; align-items: center; justify-content: center; font-size: 1.4rem; font-weight: 700; margin: 0 auto 1rem;
  }
  .alsel-subscription-benefits__card-title { font-size: 1.1rem; font-weight: 700; margin: 0 0 0.75rem; color: #1e293b; }
  .alsel-subscription-benefits__card-body { font-size: 0.95rem; line-height: 1.75; color: #475569; margin: 0; }
  .alsel-subscription-benefits__cta-wrap { margin-top: 2rem; }
  .alsel-subscription-benefits__cta {
    display: inline-block; padding: 1.1rem 2.5rem; background: var(--accent); color: #fff;
    text-decoration: none; border-radius: 9999px; font-weight: 700; font-size: 1.05rem;
    box-shadow: 0 6px 20px rgba(15, 23, 42, 0.15); transition: transform 0.2s ease, box-shadow 0.2s ease;
  }
  .alsel-subscription-benefits__cta:hover { transform: translateY(-2px); box-shadow: 0 10px 24px rgba(15, 23, 42, 0.2); }
  .alsel-subscription-benefits__cta-note { margin: 0.75rem 0 0; font-size: 0.85rem; color: #64748b; }
  @media (min-width: 750px) {
    .alsel-subscription-benefits { padding: 5rem 2rem; }
    .alsel-subscription-benefits__compare { flex-direction: row; max-width: 720px; }
    .alsel-subscription-benefits__arrow { transform: rotate(0deg); }
    .alsel-subscription-benefits__grid { grid-template-columns: repeat(3, 1fr); }
  }
</style>

